// @vitest-environment node
/**
 * SPEC-020: Capturas — la búsqueda global (SPEC-018) emite hits de entrevistas
 * SIN empresa (companyId/companyName null, discoveryId propio) en lugar de
 * omitirlas, manteniendo la omisión defensiva solo para referencias rotas.
 * Generated by QA Dev agent.
 */
import { mkdtempSync, writeFileSync } from 'fs'
import { tmpdir } from 'os'
import { join } from 'path'
import { beforeEach, describe, expect, it, vi } from 'vitest'
import * as repository from '../../../src/main/db/repository'
import { searchGlobal } from '../../../src/main/db/search'
import { initStore } from '../../../src/main/db/store'

vi.mock('electron', () => ({
  app: {
    getPath: (): string => {
      throw new Error('app.getPath no debe usarse en tests: initStore recibe baseDir inyectado')
    }
  }
}))

let baseDir = ''

beforeEach(() => {
  baseDir = mkdtempSync(join(tmpdir(), 'maurya-search-captures-'))
  initStore(baseDir)
})

describe('searchGlobal (SPEC-020 capturas)', () => {
  // SPEC-020 · AC-34 (main: el hit sin empresa viaja con companyId/companyName null)
  it('emits interview hits without company carrying null companyId/companyName and the interview discoveryId', () => {
    const discovery = repository.createDiscovery({ name: 'Vertical Sanidad' })
    const capture = repository.createInterview({
      discoveryId: discovery.id,
      title: 'Captura de dolor sin empresa'
    })

    expect(searchGlobal('dolor').interviews).toEqual([
      {
        id: capture.id,
        title: 'Captura de dolor sin empresa',
        companyId: null,
        discoveryId: discovery.id,
        companyName: null,
        status: 'draft'
      }
    ])
  })

  // SPEC-020 · AC-34 (refuerzo: la omisión defensiva se mantiene SOLO para un
  // companyId no-null que no resuelve — dato inconsistente escrito a mano)
  it('still omits interviews whose non-null companyId does not resolve', () => {
    const now = '2026-07-01T09:00:00.000Z'
    writeFileSync(
      join(baseDir, 'db.json'),
      JSON.stringify({
        schemaVersion: 2,
        discoveries: [{ id: 'd-1', name: 'Vertical Sanidad', createdAt: now, updatedAt: now }],
        companies: [],
        contacts: [],
        interviewTemplates: [],
        interviews: [
          {
            id: 'i-broken',
            discoveryId: 'd-1',
            companyId: 'c-ghost',
            contactId: null,
            templateId: null,
            title: 'Entrevista con empresa rota',
            status: 'draft',
            scriptMarkdown: null,
            objectives: [],
            wavPath: null,
            transcriptPath: null,
            createdAt: now,
            updatedAt: now
          }
        ],
        noteTemplates: [],
        notes: []
      })
    )
    initStore(baseDir)

    expect(searchGlobal('rota').interviews).toEqual([])
  })
})
